type Transform<Base, From, To> = {
    [K in keyof Base]: Exclude<Base[K], undefined | null> extends never ? Base[K]
        : Exclude<Base[K], undefined | null> extends From ? To | Extract<Base[K], null | undefined>
        : Exclude<Base[K], undefined | null> extends object ? Transform<Base[K], From, To>
        : Base[K];
};

type TransformJson<T> = Transform<T, Date | bigint, string>;

type Shared<I extends number> = {
    base: {
        id: `${I}`;
        when?: Date | null;
        meta: { tags: string[]; stamp: bigint };
    };
};

type SharedJson<I extends number> = {
    base: {
        id: `${I}`;
        when?: string | null;
        meta: { tags: string[]; stamp: string };
    };
};

type SharedClean<I extends number> = {
    base: {
        id: `${I}`;
        meta: { tags: string[]; note?: { count: number } };
    };
};

type Variant<I extends number> = Shared<I> & (
    | { type: 1; value: { a: Date; box: { n: bigint; arr: Date[] } } }
    | { type: 2; value: { b: bigint; box: { n: bigint; arr: Date[] } } }
    | { type: 3; value: { c: Date[]; box: { n: bigint; arr: Date[] } } }
    | { type: 4; value: { d: { n: bigint }; box: { n: bigint; arr: Date[] } } }
    | { type: 5; value: { e: [Date, bigint]; box: { n: bigint; arr: Date[] } } }
    | { type: 6; value: { f: { nested: Date[] }; box: { n: bigint; arr: Date[] } } }
    | { type: 7; value: { g: { maybe?: bigint | null }; box: { n: bigint; arr: Date[] } } }
    | { type: 8; value: { h: { arr: Array<{ when: Date }> }; box: { n: bigint; arr: Date[] } } }
);

type VariantJson<I extends number> = SharedJson<I> & (
    | { type: 1; value: { a: string; box: { n: string; arr: string[] } } }
    | { type: 2; value: { b: string; box: { n: string; arr: string[] } } }
    | { type: 3; value: { c: string[]; box: { n: string; arr: string[] } } }
    | { type: 4; value: { d: { n: string }; box: { n: string; arr: string[] } } }
    | { type: 5; value: { e: [string, string]; box: { n: string; arr: string[] } } }
    | { type: 6; value: { f: { nested: string[] }; box: { n: string; arr: string[] } } }
    | { type: 7; value: { g: { maybe?: string | null }; box: { n: string; arr: string[] } } }
    | { type: 8; value: { h: { arr: Array<{ when: string }> }; box: { n: string; arr: string[] } } }
);

type VariantClean<I extends number> = SharedClean<I> & (
    | { type: 1; value: { a: string; box: { n: number; arr: string[] } } }
    | { type: 2; value: { b: string; box: { n: number; arr: string[] } } }
    | { type: 3; value: { c: string; box: { n: number; arr: string[] } } }
    | { type: 4; value: { d: string; box: { n: number; arr: string[] } } }
    | { type: 5; value: { e: string; box: { n: number; arr: string[] } } }
    | { type: 6; value: { f: string; box: { n: number; arr: string[] } } }
    | { type: 7; value: { g: string; box: { n: number; arr: string[] } } }
    | { type: 8; value: { h: string; box: { n: number; arr: string[] } } }
);

type X<I extends number> = { root: { levels: Array<{ level2: Array<{ item: { level1: Array<{ item: { level0: Array<{ item: Variant<I>[]; variants: Variant<I>[]; sibling: { at: Date; tuple: [Date, bigint]; more: Variant<I> } }>; variants0: Variant<I>[] }; variants: Variant<I>[]; sibling: { at: Date; tuple: [Date, bigint]; more: Variant<I> } }>; variants1: Variant<I>[] }; variants: Variant<I>[]; sibling: { at: Date; tuple: [Date, bigint]; more: Variant<I> } }>; variants2: Variant<I>[] }>; alt: Variant<I>; end: Date } };
type XJson<I extends number> = { root: { levels: Array<{ level2: Array<{ item: { level1: Array<{ item: { level0: Array<{ item: VariantJson<I>[]; variants: VariantJson<I>[]; sibling: { at: string; tuple: [string, string]; more: VariantJson<I> } }>; variants0: VariantJson<I>[] }; variants: VariantJson<I>[]; sibling: { at: string; tuple: [string, string]; more: VariantJson<I> } }>; variants1: VariantJson<I>[] }; variants: VariantJson<I>[]; sibling: { at: string; tuple: [string, string]; more: VariantJson<I> } }>; variants2: VariantJson<I>[] }>; alt: VariantJson<I>; end: string } };
type XClean<I extends number> = { root: { levels: Array<{ level2: Array<{ item: { level1: Array<{ item: { level0: Array<{ item: VariantClean<I>[]; variants: VariantClean<I>[]; sibling: { ok: boolean; tuple: [string, number]; more: VariantClean<I> } }>; variants0: VariantClean<I>[] }; variants: VariantClean<I>[]; sibling: { ok: boolean; tuple: [string, number]; more: VariantClean<I> } }>; variants1: VariantClean<I>[] }; variants: VariantClean<I>[]; sibling: { ok: boolean; tuple: [string, number]; more: VariantClean<I> } }>; variants2: VariantClean<I>[] }>; alt: VariantClean<I>; end: { done: true } } };

